            ],
            "transitions": [
                {
                    "from": t.from_state,
                    "to": t.to_state,
                    "condition": t.condition,
                    "priority": t.priority,
                }
                for t in self.transitions
            ],
            "initial": self.initial_state,
            "terminal": self.terminal_states,
        }


